def _recompute(s):
    cap = s["chairs"] * len(s["sessions"])
    used = 0
    for ss in s["sessions"]:
        used += len(s["assignments"].get(ss, []))
    s["scheduled_count"] = used
    s["open_slots"] = cap - used
    s["waitlist_len"] = len(s["waitlist"])
    s["utilization"] = round(used / cap, 3) if cap else 0.0
    return s


def _fullest(s):
    booked = [ss for ss in s["sessions"] if s["assignments"].get(ss)]
    booked = sorted(booked, key=lambda ss: (-len(s["assignments"][ss]), ss))
    return booked[0] if booked else None


def _emptiest_with_room(s):
    cand = sorted(s["sessions"], key=lambda ss: (len(s["assignments"].get(ss, [])), ss))
    for ss in cand:
        if len(s["assignments"].get(ss, [])) < s["chairs"]:
            return ss
    return None


def transition(state, action):
    s = dict(state)
    s["assignments"] = {k: list(v) for k, v in s["assignments"].items()}
    s["waitlist"] = list(s["waitlist"])
    s["patients"] = dict(s["patients"])
    name = action.get("name")
    params = action.get("params") or {}

    if name == "schedule":
        # 1) admit a perceived referral onto the waitlist.
        pid = s.get("pending_patient") or ""
        if pid:
            need = int(s.get("pending_need") or 0)
            s["patients"][pid] = need
            for _ in range(max(need, 0)):
                s["waitlist"].append(pid)
            s["pending_patient"] = ""
            s["pending_need"] = 0
        # 2) seat the next waiting patient in an open chair.
        patient = params.get("patient")
        if patient is None and s["waitlist"]:
            patient = s["waitlist"][0]
        if patient is not None:
            session = params.get("session")
            target = None
            if session in s["sessions"]:
                lst = s["assignments"].get(session, [])
                if len(lst) < s["chairs"] and patient not in lst:
                    target = session
            else:
                for ss in s["sessions"]:
                    lst = s["assignments"].setdefault(ss, [])
                    if len(lst) < s["chairs"] and patient not in lst:
                        target = ss
                        break
            if target is not None:
                s["assignments"].setdefault(target, []).append(patient)
                if patient in s["waitlist"]:
                    s["waitlist"].remove(patient)

    elif name == "swap":
        frm = params.get("from_session")
        to = params.get("to_session")
        if frm not in s["sessions"]:
            frm = _fullest(s)
        if to not in s["sessions"]:
            to = _emptiest_with_room(s)
        if frm and to and frm != to and s["assignments"].get(frm):
            patient = params.get("patient")
            if patient not in s["assignments"].get(frm, []):
                patient = s["assignments"][frm][-1]
            dst = s["assignments"].setdefault(to, [])
            if len(dst) < s["chairs"] and patient not in dst:
                s["assignments"][frm].remove(patient)
                dst.append(patient)
                s["swaps"] = s.get("swaps", 0) + 1

    elif name == "miss":
        session = params.get("session")
        if session not in s["sessions"] or not s["assignments"].get(session):
            session = _fullest(s)
        if session and s["assignments"].get(session):
            patient = params.get("patient")
            if patient not in s["assignments"][session]:
                patient = s["assignments"][session][-1]
            s["assignments"][session].remove(patient)
            s["missed_count"] = s.get("missed_count", 0) + 1
            # the recurring need did not go away — it returns to the waitlist.
            s["waitlist"].append(patient)

    s["tick"] = s.get("tick", 0) + 1
    return _recompute(s)

