def perceive(data):
    text = str(data).lower().replace("\n", ";")
    patient = ""
    need = 0
    for part in text.split(";"):
        if ":" not in part:
            continue
        k, v = part.split(":", 1)
        k = k.strip()
        v = v.strip()
        if k in ("patient", "name", "id") and v:
            patient = v.split()[0]
        elif k in ("need", "sessions", "frequency", "need_per_week"):
            digits = "".join(ch for ch in v if ch.isdigit())
            need = int(digits) if digits else 0
    if need < 0:
        need = 0
    if need > 7:
        need = 7
    return {"pending_patient": patient, "pending_need": need}
